div.script:
                    //
(function () {
    'use strict';
    var bell     = document.getElementById('notifBell');
    var dropdown = document.getElementById('notifDropdown');

    bell.addEventListener('click', function (e) {
        e.stopPropagation();
        dropdown.classList.toggle('open');
    });
    document.addEventListener('click', function () { dropdown.classList.remove('open'); });
    dropdown.addEventListener('click', function (e) { e.stopPropagation(); });

    document.getElementById('markAllRead').addEventListener('click', function () {
        document.querySelectorAll('.notif-item').forEach(function (i) { i.classList.remove('unread'); });
        document.getElementById('notifBadge').classList.add('d-none');
    });

    document.querySelectorAll('.notif-nav-link').forEach(function (a) {
        a.addEventListener('click', function (e) {
            e.preventDefault();
            window.switchView(this.getAttribute('data-view'));
            dropdown.classList.remove('open');
        });
    });

    function loadSlaAlerts() {
        fetch('/customer_support/dashboard/sla_alerts', {
            method: 'GET', credentials: 'same-origin', headers: { 'Accept': 'application/json' }
        })
        .then(function (r) { if (!r.ok) throw new Error(r.status); return r.json(); })
        .then(function (data) { renderAlerts(data.alerts || []); })
        .catch(function () { renderAlerts([]); });
    }

    function renderAlerts(alerts) {
        var list  = document.getElementById('notifList');
        var badge = document.getElementById('notifBadge');
        if (!alerts.length) {
            list.innerHTML = '<div class="notif-empty"><i class="bi bi-check-circle-fill" style="font-size:2rem;color:#22c55e;display:block;margin-bottom:.5rem;"></i>All tickets are on track!</div>';
            badge.classList.add('d-none');
            return;
        }
        badge.textContent = alerts.length;
        badge.classList.remove('d-none');
        list.innerHTML = alerts.map(function (a) {
            var cls   = a.sla_status === 'breached' ? 'breached' : 'at-risk';
            var icon  = cls === 'breached' ? 'bi-x-octagon-fill' : 'bi-exclamation-triangle-fill';
            var label = cls === 'breached' ? 'SLA Breached' : 'At Risk';
            return '<a class="notif-item unread" href="/customer_support/ticket/' + a.ticket_id + '">'
                + '<div class="notif-icon-wrap ' + cls + '"><i class="bi ' + icon + '"></i></div>'
                + '<div class="notif-body">'
                + '<div class="notif-title">' + a.ticket_name + ' \u2014 ' + a.subject + '</div>'
                + '<div class="notif-sub">' + label + ' \u00b7 ' + a.time_display + '</div>'
                + '<div class="notif-time-text">Policy: ' + (a.policy_name || 'None') + '</div>'
                + '</div><div class="notif-dot ' + cls + '"></div></a>';
        }).join('');
    }

    document.addEventListener('DOMContentLoaded', function () {
        loadSlaAlerts();
        setInterval(loadSlaAlerts, 30000);
    });
})();
//

                    //
(function () {
    'use strict';
    var INTERVAL = 15000;
    var A = [
        { key: 'open_tickets',    sel: '[data-key="open_tickets"] .stat-value' },
        { key: 'total_tickets',   sel: '[data-key="total_tickets"] .stat-value' },
        { key: 'high_priority',   sel: '[data-key="high_priority"] .stat-value' },
        { key: 'urgent',          sel: '[data-key="urgent"] .stat-value' },
        { key: 'avg_open_hours',  sel: '[data-key="avg_open_hours"] .stat-value' },
        { key: 'total_hours',     sel: '[data-key="total_hours"] .stat-value' },
        { key: 'avg_high_hours',  sel: '[data-key="avg_high_hours"] .stat-value' },
        { key: 'avg_urgent_hours',sel: '[data-key="avg_urgent_hours"] .stat-value' },
        { key: 'resolved_tickets',sel: '[data-key="resolved_tickets"] .stat-value' },
        { key: 'solve_rate',      sel: '[data-key="solve_rate"] .stat-value', sfx: '%' },
        { key: 'high_resolved',   sel: '[data-key="high_resolved"] .stat-value' },
        { key: 'urgent_resolved', sel: '[data-key="urgent_resolved"] .stat-value' }
    ];
    var P = [
        { key: 'today_closed',      sel: '[data-key="today_closed"] .performance-value' },
        { key: 'avg_resolve_rate',  sel: '[data-key="avg_resolve_rate"] .performance-value', sfx: '%' },
        { key: 'daily_target',      sel: '[data-key="daily_target"] .performance-value', sfx: '%' },
        { key: 'achievement',       sel: '[data-key="achievement"] .performance-value', sfx: '%' },
        { key: 'sample_performance',sel: '[data-key="sample_performance"] .score-badge', sfx: '%' }
    ];

    function upd(sel, val, sfx) { var el = document.querySelector(sel); if (el) el.textContent = val + (sfx || ''); }
    function flash(sel) {
        var el = document.querySelector(sel);
        if (el) { el.style.transition = 'color 0.3s'; el.style.color = '#1e88c7'; setTimeout(function () { el.style.color = ''; }, 600); }
    }
    function updBar(v) {
        var b = document.querySelector('.progress-bar');
        if (b) { b.style.width = v + '%'; b.className = 'progress-bar ' + (v >= 80 ? 'bg-success' : 'bg-warning'); }
    }
    function updBarLabel(v) {
        var ls = document.querySelectorAll('.progress-label span');
        if (ls.length >= 2) ls[1].textContent = v + '%';
    }
    function updTime() {
        var t = new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
        document.querySelectorAll('.last-updated').forEach(function (el) {
            el.innerHTML = '<i class="bi bi-clock me-1"></i>Updated at ' + t;
        });
    }

    function run() {
        fetch('/customer_support/dashboard/analytics', {
            method: 'GET', credentials: 'same-origin', headers: { 'Accept': 'application/json' }
        })
        .then(function (r) { if (!r.ok) throw new Error(r.status); return r.json(); })
        .then(function (d) {
            var a = d.analytics || {}, p = d.performance || {};
            A.forEach(function (i) { var v = a[i.key]; if (v !== undefined) { upd(i.sel, v, i.sfx || ''); flash(i.sel); } });
            P.forEach(function (i) { var v = p[i.key]; if (v !== undefined) upd(i.sel, v, i.sfx || ''); });
            if (p.achievement !== undefined) { updBar(p.achievement); updBarLabel(p.achievement); }
            updTime();
        })
        .catch(function (e) { console.warn('Analytics refresh failed:', e); });
    }

    document.addEventListener('DOMContentLoaded', function () { run(); setInterval(run, INTERVAL); });
})();
//

                    //
document.addEventListener('DOMContentLoaded', function () {

    // ── Auto-hide flash alerts ────────────────────────────────────────────
    setTimeout(function () {
        document.querySelectorAll('.alert').forEach(function (a) { new bootstrap.Alert(a).close(); });
    }, 5000);

    // ── Spinner keyframe (added once) ────────────────────────────────────
    var spinStyle = document.createElement('style');
    spinStyle.textContent = '@keyframes spin { to { transform: rotate(360deg); } }';
    document.head.appendChild(spinStyle);

    // ── Toast helper ─────────────────────────────────────────────────────
    var toastEl = document.getElementById('kanbanToast');
    var toastTimer;
    function showToast(msg, type) {
        toastEl.textContent = msg;
        toastEl.className   = 'show ' + (type || '');
        clearTimeout(toastTimer);
        toastTimer = setTimeout(function () { toastEl.className = ''; }, 3000);
    }

    // ── Page switching ────────────────────────────────────────────────────
    window.switchView = function (viewId) {
        // Desktop nav links
        document.querySelectorAll('.header-nav .nav-link').forEach(function (l) { l.classList.remove('active'); });
        var nl = document.querySelector('.header-nav .nav-link[data-view="' + viewId + '"]');
        if (nl) nl.classList.add('active');

        // Mobile drawer items — keep in sync
        document.querySelectorAll('.mobile-nav-item').forEach(function (i) { i.classList.remove('active'); });
        var mni = document.querySelector('.mobile-nav-item[data-view="' + viewId + '"]');
        if (mni) mni.classList.add('active');

        // Pages
        document.querySelectorAll('.page-content').forEach(function (p) { p.style.display = 'none'; });
        var target = document.getElementById(viewId + '-page');
        if (target) target.style.display = 'block';
    };

    document.querySelectorAll('.header-nav .nav-link').forEach(function (link) {
        link.addEventListener('click', function (e) { e.preventDefault(); window.switchView(this.getAttribute('data-view')); });
    });
    document.querySelectorAll('.action-card[data-view]').forEach(function (card) {
        card.addEventListener('click', function (e) { e.preventDefault(); window.switchView(this.getAttribute('data-view')); });
    });

    // ── List / Kanban view toggle (desktop buttons) ───────────────────────
    var listViewBtn   = document.getElementById('listViewBtn');
    var kanbanViewBtn = document.getElementById('kanbanViewBtn');
    var listView      = document.getElementById('listView');
    var kanbanView    = document.getElementById('kanbanView');

    function showList() {
        listView.style.display   = 'block';
        kanbanView.style.display = 'none';
        listViewBtn.classList.add('active');
        kanbanViewBtn.classList.remove('active');
        // Sync mobile pill
        document.getElementById('mobilePillList').classList.add('active');
        document.getElementById('mobilePillKanban').classList.remove('active');
    }
    function showKanban() {
        listView.style.display   = 'none';
        kanbanView.style.display = 'block';
        listViewBtn.classList.remove('active');
        kanbanViewBtn.classList.add('active');
        // Sync mobile pill
        document.getElementById('mobilePillList').classList.remove('active');
        document.getElementById('mobilePillKanban').classList.add('active');
        updateCounts();
    }
    listViewBtn.addEventListener('click', showList);
    kanbanViewBtn.addEventListener('click', showKanban);

    // ── Mobile pill toggle ────────────────────────────────────────────────
    document.getElementById('mobilePillList').addEventListener('click', function () {
        showList();
    });
    document.getElementById('mobilePillKanban').addEventListener('click', function () {
        showKanban();
    });

    // ── Header kanban shortcut ───────────────────────────────────────────
    document.getElementById('kanbanToggleBtn').addEventListener('click', function () {
        window.switchView('tickets');
        showKanban();
        this.classList.toggle('active');
    });

    // ── Column counts ─────────────────────────────────────────────────────
    function updateCounts() {
        ['new', 'in_progress', 'resolved', 'closed'].forEach(function (s) {
            var col = document.getElementById('col-' + s);
            var cnt = document.getElementById('count-' + s);
            if (col && cnt) cnt.textContent = col.querySelectorAll('.kanban-card').length;
        });
    }

    // ── Mobile kanban column collapse ─────────────────────────────────────
    document.querySelectorAll('.kanban-col-header[data-col-toggle]').forEach(function (header) {
        header.addEventListener('click', function () {
            // Only collapse on mobile — guard with CSS class check
            if (window.innerWidth > 768) return;
            var col = this.closest('.kanban-col');
            col.classList.toggle('collapsed');
            var chevron = this.querySelector('.kanban-col-chevron');
            if (chevron) {
                chevron.classList.toggle('bi-chevron-down');
                chevron.classList.toggle('bi-chevron-up');
            }
        });
    });

    // ── Search ────────────────────────────────────────────────────────────
    var searchInput = document.querySelector('.search-input');
    function applySearch() {
        if (!searchInput) return;
        var term = searchInput.value.toLowerCase();
        document.querySelectorAll('.ticket-row').forEach(function (r) {
            r.style.display = r.textContent.toLowerCase().includes(term) ? '' : 'none';
        });
        document.querySelectorAll('.kanban-card').forEach(function (c) {
            c.style.display = c.textContent.toLowerCase().includes(term) ? '' : 'none';
        });
    }
    if (searchInput) searchInput.addEventListener('input', applySearch);

    // ════════════════════════════════════════════════════════════════════
    //  TICKET POLLING ENGINE
    // ════════════════════════════════════════════════════════════════════
    var _renderedIds = {};
    var _firstLoad   = true;

    function toColState(state) {
        if (state === 'assigned' || state === 'new') return 'new';
        if (state === 'in_progress') return 'in_progress';
        if (state === 'resolved')    return 'resolved';
        if (state === 'closed')      return 'closed';
        return 'new';
    }

    function stateLabel(state) {
        var map = { new:'New', assigned:'Assigned', in_progress:'In Progress', resolved:'Resolved', closed:'Closed' };
        return map[state] || state.replace(/_/g, ' ').replace(/\b\w/g, function (c) { return c.toUpperCase(); });
    }

    function stateCssClass(state) {
        if (state === 'new' || state === 'assigned') return 'status-new';
        if (state === 'in_progress') return 'status-in-progress';
        if (state === 'resolved')    return 'status-resolved';
        if (state === 'closed')      return 'status-closed';
        return 'status-new';
    }

    function buildListRow(t) {
        var av  = t.customer_id ? '/web/image/res.partner/' + t.customer_id + '/avatar_128' : '/web/static/img/avatar_gray.svg';
        var sc  = stateCssClass(t.state);
        var sd  = stateLabel(t.state);
        var pc  = 'priority-' + (t.priority || 'low');
        var pl  = (t.priority || 'low').charAt(0).toUpperCase() + (t.priority || 'low').slice(1);
        return '<tr class="ticket-row" data-ticket-id="' + t.id + '" style="cursor:pointer;">'
            + '<td class="ticket-info-col"><div class="ticket-id-badge">' + escHtml(t.name) + '</div><div class="ticket-description">' + escHtml(t.subject || 'No description') + '</div></td>'
            + '<td class="customer-col"><div class="customer-info"><img src="' + av + '" class="customer-avatar" onerror="this.src=\'/web/static/img/avatar_gray.svg\'" /><span class="customer-name">' + escHtml(t.customer_name) + '</span></div></td>'
            + '<td class="status-col"><span class="table-status-badge ' + sc + '">' + sd + '</span></td>'
            + '<td class="priority-col"><span class="table-priority-badge ' + pc + '">' + pl + '</span></td>'
            + '<td class="created-col">' + escHtml(t.create_date) + '</td>'
            + '<td class="project-col"><i class="bi bi-folder2"></i> <span>Support</span></td>'
            + '</tr>';
    }

    function buildKanbanCard(t) {
        var av = t.customer_id ? '/web/image/res.partner/' + t.customer_id + '/avatar_128' : '/web/static/img/avatar_gray.svg';
        var pc = 'priority-' + (t.priority || 'low');
        var pl = (t.priority || 'low').charAt(0).toUpperCase() + (t.priority || 'low').slice(1);
        return '<div class="kanban-card" data-ticket-id="' + t.id + '" data-state="' + toColState(t.state) + '" draggable="true">'
            + '<div class="kanban-card-id">' + escHtml(t.name) + '</div>'
            + '<div class="kanban-card-subject">' + escHtml(t.subject || '') + '</div>'
            + '<div class="kanban-card-footer"><div class="kanban-card-customer"><img src="' + av + '" onerror="this.src=\'/web/static/img/avatar_gray.svg\'" /><span>' + escHtml(t.customer_name) + '</span></div>'
            + '<span class="kanban-priority ' + pc + '">' + pl + '</span></div></div>';
    }

    function escHtml(str) {
        return String(str).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
    }

    function renderTickets(tickets) {
        var newIds = {};
        tickets.forEach(function (t) { newIds[t.id] = true; });
        var addedIds = [];
        if (!_firstLoad) {
            tickets.forEach(function (t) { if (!_renderedIds[t.id]) addedIds.push(t.id); });
        }
        _renderedIds = newIds;
        _firstLoad   = false;

        var tbody      = document.getElementById('ticketTableBody');
        var table      = document.getElementById('ticketTable');
        var emptyState = document.getElementById('ticketsEmptyState');
        var loading    = document.getElementById('ticketsLoadingState');
        loading.style.display = 'none';
        if (tickets.length === 0) {
            table.style.display      = 'none';
            emptyState.style.display = 'block';
        } else {
            emptyState.style.display = 'none';
            table.style.display      = '';
            tbody.innerHTML          = tickets.map(buildListRow).join('');
            bindRowClicks();
        }

        var cols = { new: [], in_progress: [], resolved: [], closed: [] };
        tickets.forEach(function (t) { cols[toColState(t.state)].push(t); });

        ['new', 'in_progress', 'resolved', 'closed'].forEach(function (state) {
            var colEl = document.getElementById('col-' + state);
            if (!colEl) return;
            var existingIds = {};
            colEl.querySelectorAll('.kanban-card').forEach(function (card) {
                existingIds[card.getAttribute('data-ticket-id')] = card;
            });
            cols[state].forEach(function (t) {
                var tid = String(t.id);
                if (!existingIds[tid]) {
                    var tmp = document.createElement('div');
                    tmp.innerHTML = buildKanbanCard(t);
                    var newCard = tmp.firstChild;
                    colEl.appendChild(newCard);
                    if (addedIds.indexOf(t.id) !== -1) {
                        newCard.classList.add('ticket-new-flash');
                        showToast('\uD83D\uDCCB New ticket assigned: ' + t.name, 'success');
                    }
                }
            });
            var incomingIds = {};
            cols[state].forEach(function (t) { incomingIds[String(t.id)] = true; });
            Object.keys(existingIds).forEach(function (tid) {
                if (!incomingIds[tid]) existingIds[tid].remove();
            });
        });

        updateCounts();
        applySearch();
        bindDragDrop();
    }

    function loadTickets() {
        fetch('/customer_support/dashboard/tickets', {
            method: 'GET', credentials: 'same-origin', headers: { 'Accept': 'application/json' }
        })
        .then(function (r) { if (!r.ok) throw new Error(r.status); return r.json(); })
        .then(function (data) { renderTickets(data.tickets || []); })
        .catch(function (e) { console.warn('Ticket refresh failed:', e); });
    }

    loadTickets();
    setInterval(loadTickets, 20000);

    function bindRowClicks() {
        document.querySelectorAll('.ticket-row').forEach(function (row) {
            row.addEventListener('click', function () {
                var id = this.getAttribute('data-ticket-id');
                if (id) window.location.href = '/customer_support/ticket/' + id;
            });
        });
    }

    var draggedCard = null;
    function bindDragDrop() {}

    document.addEventListener('dragstart', function (e) {
        var card = e.target.closest('.kanban-card');
        if (!card) return;
        draggedCard = card;
        card.classList.add('dragging');
        e.dataTransfer.effectAllowed = 'move';
        e.dataTransfer.setData('text/plain', card.getAttribute('data-ticket-id'));
    });

    document.addEventListener('dragend', function (e) {
        var card = e.target.closest('.kanban-card');
        if (card) card.classList.remove('dragging');
        document.querySelectorAll('.kanban-col').forEach(function (col) { col.classList.remove('drag-over'); });
        draggedCard = null;
    });

    document.querySelectorAll('.kanban-col').forEach(function (col) {
        col.addEventListener('dragover', function (e) {
            e.preventDefault();
            e.dataTransfer.dropEffect = 'move';
            this.classList.add('drag-over');
        });
        col.addEventListener('dragleave', function (e) {
            if (!this.contains(e.relatedTarget)) this.classList.remove('drag-over');
        });
        col.addEventListener('drop', function (e) {
            e.preventDefault();
            this.classList.remove('drag-over');
            if (!draggedCard) return;
            var newState = this.getAttribute('data-state');
            var ticketId = draggedCard.getAttribute('data-ticket-id');
            var oldState = draggedCard.getAttribute('data-state');
            if (oldState === newState) return;
            var cardsContainer = this.querySelector('.kanban-cards');
            cardsContainer.appendChild(draggedCard);
            draggedCard.setAttribute('data-state', newState);
            _renderedIds[ticketId] = true;
            updateCounts();
            saveTicketStatus(ticketId, newState);
        });
    });

    function saveTicketStatus(ticketId, newState) {
        var fd = new FormData();
        fd.append('status', newState);
        fetch('/customer_support/ticket/' + ticketId + '/update_status', {
            method: 'POST', body: fd, credentials: 'same-origin', headers: { 'Accept': 'application/json' }
        })
        .then(function (r) { return r.json(); })
        .then(function (data) {
            if (data.success) { showToast('\u2713 Saved \u2014 ' + newState.replace(/_/g, ' '), 'success'); }
            else { showToast('\u2717 ' + (data.error || 'Save failed'), 'error'); }
        })
        .catch(function (e) { console.warn('Status update error:', e); showToast('\u2717 Network error', 'error'); });
    }

    document.addEventListener('click', function (e) {
        var card = e.target.closest('.kanban-card');
        if (!card || card.classList.contains('dragging')) return;
        var id = card.getAttribute('data-ticket-id');
        if (id) window.location.href = '/customer_support/ticket/' + id;
    });

});
//

                    //
(function () {
    'use strict';
    var hamburger = document.getElementById('mobileHamburgerBtn');
    var overlay   = document.getElementById('mobileNavOverlay');
    var drawer    = document.getElementById('mobileNavDrawer');
    var closeBtn  = document.getElementById('mobileNavClose');

    function openDrawer() {
        drawer.classList.add('open');
        overlay.classList.add('open');
        document.body.style.overflow = 'hidden';
    }

    function closeDrawer() {
        drawer.classList.remove('open');
        overlay.classList.remove('open');
        document.body.style.overflow = '';
    }

    if (hamburger) hamburger.addEventListener('click', openDrawer);
    if (closeBtn)  closeBtn.addEventListener('click', closeDrawer);
    if (overlay)   overlay.addEventListener('click', closeDrawer);

    if (drawer) {
        drawer.querySelectorAll('.mobile-nav-item').forEach(function (item) {
            item.addEventListener('click', function () {
                var viewId = this.getAttribute('data-view');

                // Update active state in drawer
                drawer.querySelectorAll('.mobile-nav-item').forEach(function (i) { i.classList.remove('active'); });
                this.classList.add('active');

                // Switch the page view
                if (window.switchView) window.switchView(viewId);

                closeDrawer();
            });
        });
    }
})();
//
